use alloc::{
    format,
    string::{String, ToString},
    sync::Arc,
};

use axerrno::LinuxResult;
use axfs::{FS_CONTEXT, FsContext, OpenOptions, OpenResult};
use axfs_ng_vfs::NodePermission;
use axhal::uspace::UserContext;
use axsync::Mutex;
use axtask::{AxTaskExt, spawn_task};
use starry_process::{Pid, Process};

use crate::{
    file::FD_TABLE,
    mm::{copy_from_kernel, linux_exec_vecs, load_user_app, new_user_aspace_empty},
    net::NET_NS,
    pseudofs::{self, dev::tty::N_TTY},
    task::{ProcessData, Thread, add_task_to_table, new_user_task, spawn_alarm_task},
};


/// Initialize and run initproc.
pub fn init(args: &[String], envs: &[String]) {
    init_with_ltp_whitelist(args, envs);
}

/// Initialize and run initproc; materializes embedded LTP whitelist when SD image lacks it.
pub fn init_with_ltp_whitelist(args: &[String], envs: &[String]) {
    pseudofs::mount_all().expect("Failed to mount pseudofs");
    crate::syscall::module::register_builtin_modules();
    crate::net::bootstrap_ltp_veth();
    crate::net::sync_current_netns_ifaces_sysfs();
    spawn_alarm_task();

    let mut merged_envs: alloc::vec::Vec<String> = envs.to_vec();
    if let Some((path, lines)) = bootstrap_ltp_whitelist() {
        merged_envs.push(format!("LTP_WHITELIST_PATH={path}"));
        merged_envs.push(format!("LTP_WHITELIST_LINES={lines}"));
    }

    let mut resolved_args = resolve_init_exec_args(args.to_vec());

    let loc = FS_CONTEXT
        .lock()
        .resolve(&resolved_args[0])
        .expect("Failed to resolve executable path");
    let path = loc
        .absolute_path()
        .expect("Failed to get executable absolute path");
    let name = loc.name();

    let mut uspace = new_user_aspace_empty()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");

    let (entry_vaddr, ustack_top, exe_cache) =
        load_user_app(&mut uspace, None, &resolved_args, &merged_envs)
            .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));

    let argc = resolved_args.len();
    let mut uctx = UserContext::new(entry_vaddr.into(), ustack_top, argc);
    let (_, argv_ptr, envp_ptr) = linux_exec_vecs(ustack_top.as_usize(), argc);
    uctx.set_arg1(argv_ptr);
    uctx.set_arg2(envp_ptr);
    let mut task = new_user_task(name, uctx, 0);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let pid = task.id().as_u64() as Pid;
    let proc = Process::new_init(pid);
    proc.add_thread(pid);

    N_TTY.bind_to(&proc).expect("Failed to bind ntty");

    let proc = ProcessData::new(
        proc,
        path.to_string(),
        Arc::new(resolved_args),
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        None,
    );
    *proc.exe_cache.write() = Some(exe_cache);

    {
        let mut scope = proc.scope.write();
        crate::file::add_stdio(&mut FD_TABLE.scope_mut(&mut scope).write())
            .expect("Failed to add stdio");
        NET_NS.scope_mut(&mut scope).clone_from(&NET_NS);
    }

    let thr = Thread::new(pid, proc);
    *task.task_ext_mut() = Some(AxTaskExt::from_impl(thr));

    let task = spawn_task(task);
    add_task_to_table(&task);

    // TODO: wait for all processes to finish
    let exit_code = task.join();
    info!("Init process exited with code: {exit_code:?}");

    let cx = FS_CONTEXT.lock();
    if let Err(e) = cx.root_dir().unmount_all() {
        warn!("Failed to unmount all filesystems: {:?}", e);
    }
    if let Err(e) = cx.root_dir().filesystem().flush() {
        warn!("Failed to flush rootfs: {:?}", e);
    }
}

fn bootstrap_ltp_whitelist() -> Option<(String, usize)> {
    // Always use the compiled-in whitelist (up-to-date with source).
    // The SD card image may contain a stale copy.
    let filtered = crate::ltp_whitelist::filter_whitelist(
        include_str!(concat!(env!("OUT_DIR"), "/ltp_whitelist.txt")),
    );
    if filtered.is_empty() {
        // Fall back to filesystem whitelist if embedded is empty.
        let fs = FS_CONTEXT.lock();
        for cand in [
            "/tmp/starry_ltp_whitelist.txt",
            "/musl/ltp_whitelist.txt",
            "/glibc/ltp_whitelist.txt",
            "/etc/ltp_whitelist.txt",
        ] {
            let Ok(loc) = fs.resolve(cand) else {
                continue;
            };
            if loc.len().unwrap_or(0) > 0 {
                info!("LTP whitelist: using rootfs file {cand}");
                return Some((cand.to_string(), 0));
            }
        }
        drop(fs);
        return None;
    }
    let lines = filtered.lines().filter(|l| !l.is_empty()).count();
    let nbytes = filtered.len();
    if let Some(_path) = materialize_ltp_whitelist_file(&filtered) {
        info!(
            "LTP whitelist: materialized {nbytes} bytes; env path {}",
            crate::ltp_whitelist::PROC_PATH
        );
        return Some((crate::ltp_whitelist::PROC_PATH.to_string(), lines));
    }
    let path = crate::ltp_whitelist::DEV_PATH;
    info!("LTP whitelist: serving {nbytes} bytes at {path}");
    Some((path.to_string(), lines))
}

const TMP_LTP_WHITELIST: &str = "/tmp/starry_ltp_whitelist.txt";
const TMP_INIT_SCRIPT: &str = "/tmp/starry_init.sh";
const TMP_BOOT_SCRIPT: &str = "/tmp/starry_boot.sh";
const ETC_LTP_WHITELIST: &str = "/etc/ltp_whitelist.txt";
const DIR_PERMISSION: NodePermission = NodePermission::from_bits_truncate(0o755);

/// Loop-free launcher executed first. Some LoongArch rootfs busybox builds ship a
/// weak shell (hush / stripped ash) that cannot parse the full init script (it
/// aborts at the first `for ... done`), while RISC-V busybox ash parses it fine.
/// This launcher uses only `if/fi`, `[ -x ]`, `&&` and `exec` — syntax every
/// busybox shell handles — and execs the first busybox whose `sh -n` accepts the
/// real script. On RISC-V the first candidate (/musl/busybox) passes `sh -n`, so
/// the effective behaviour is identical to a direct `busybox sh /tmp/starry_init.sh`.
const INIT_BOOT_LAUNCHER: &str = "\
_starry_real=/tmp/starry_init.sh\n\
if [ -x /musl/busybox ]; then exec /musl/busybox sh \"$_starry_real\"; fi\n\
if [ -x /glibc/busybox ]; then exec /glibc/busybox sh \"$_starry_real\"; fi\n\
if [ -x /bin/busybox ]; then exec /bin/busybox sh \"$_starry_real\"; fi\n\
if [ -x /busybox ]; then exec /busybox sh \"$_starry_real\"; fi\n\
exec /bin/sh \"$_starry_real\"\n";

const BUSYBOX_CANDIDATES: &[&str] = &[
    "/musl/busybox",
    "/glibc/busybox",
    "/bin/busybox",
    "/busybox",
];

fn resolve_busybox() -> Option<String> {
    let fs = FS_CONTEXT.lock();
    for cand in BUSYBOX_CANDIDATES {
        if fs.resolve(cand).is_ok() {
            return Some(cand.to_string());
        }
    }
    None
}

/// Turn `sh -c <embedded init.sh>` into `busybox sh /tmp/starry_init.sh`.
///
/// Avoids passing ~180KiB script on the user stack (LoongArch init failures) and
/// avoids rootfs `/bin/sh` stubs that lack busybox-ash function syntax.
fn resolve_init_exec_args(mut args: alloc::vec::Vec<String>) -> alloc::vec::Vec<String> {
    if args.len() >= 3 && args[1] == "-c" {
        let script = args.pop().expect("checked len");
        args.pop(); // "-c"
        let _sh = args.pop(); // "/bin/sh" or similar
        if !write_init_script(TMP_INIT_SCRIPT, &script) {
            panic!("Failed to materialize init script at {TMP_INIT_SCRIPT}");
        }
        if !write_launcher_script(TMP_BOOT_SCRIPT, INIT_BOOT_LAUNCHER) {
            panic!("Failed to materialize boot launcher at {TMP_BOOT_SCRIPT}");
        }
        let busybox = resolve_busybox().unwrap_or_else(|| {
            panic!(
                "init.sh requires busybox ash (/musl/busybox or /glibc/busybox); \
                 plain /bin/sh cannot parse the embedded init script"
