    PROCESS_TABLE.read().values().collect()
}

/// Returns true if `pid` is visible under `/proc/<pid>` (same sources as procfs).
pub fn proc_pid_exists(pid: Pid) -> bool {
    proc_pid_visible(pid)
}

/// Like [`proc_pid_exists`], but also accepts zombie entries kept in the process tree.
pub fn proc_pid_visible(pid: Pid) -> bool {
    if pid == 0 {
        return true;
    }
    if get_process_data(pid).is_ok() || get_task(pid).is_ok() {
        return true;
    }
    if tasks()
        .iter()
        .any(|t| t.as_thread().proc_data.proc.pid() == pid)
    {
        return true;
    }
    for proc_data in processes() {
        if proc_data.proc.pid() == pid {
            return true;
        }
        if proc_data.proc.threads().iter().any(|&tid| tid == pid) {
            return true;
        }
    }
    // LTP `tst_ns_create` daemon may exit after registering its netns; keep /proc/<pid>
    // reachable so `[ -f /var/run/netns/ltp_ns ]` (symlink -> /proc/<pid>/ns/net) works.
    lookup_pid_netns(pid).is_some()
}

