pub fn get_process_data(pid: Pid) -> AxResult<Arc<ProcessData>> {
    if pid == 0 {
        return Ok(current().as_thread().proc_data.clone());
    }
    if let Some(data) = PROCESS_TABLE.read().get(&pid) {
        return Ok(data);
    }
    for task in tasks() {
        if task.as_thread().proc_data.proc.pid() == pid {
            return Ok(task.as_thread().proc_data.clone());
        }
    }
    Err(AxError::NoSuchProcess)
}

/// Finds the process group with the given PGID.
pub fn get_process_group(pgid: Pid) -> AxResult<Arc<ProcessGroup>> {
    PROCESS_GROUP_TABLE
        .read()
        .get(&pgid)
        .ok_or(AxError::NoSuchProcess)
}

/// Finds the session with the given SID.
pub fn get_session(sid: Pid) -> AxResult<Arc<Session>> {
    SESSION_TABLE.read().get(&sid).ok_or(AxError::NoSuchProcess)
}

/// Spin/yield attempts when syscall paths contend with `alarm_task` on `TimeManager`.
const TIME_BORROW_SPIN: usize = 256;

/// Mutably borrow the current thread's [`TimeManager`], yielding on `RefCell` conflict.
pub(crate) fn borrow_thread_time_mut(
    thr: &Thread,
) -> Result<core::cell::RefMut<'_, TimeManager>, axerrno::AxError> {
    use axerrno::{AxError, LinuxError};
    for _ in 0..TIME_BORROW_SPIN {
        if let Ok(guard) = thr.time.try_borrow_mut() {
            return Ok(guard);
        }
        axtask::yield_now();
    }
    thr.time
        .try_borrow_mut()
        .map_err(|_| AxError::from(LinuxError::EAGAIN))
}

/// Immutably borrow the current thread's [`TimeManager`], yielding on `RefCell` conflict.
pub(crate) fn borrow_thread_time(
    thr: &Thread,
) -> Result<core::cell::Ref<'_, TimeManager>, axerrno::AxError> {
    use axerrno::{AxError, LinuxError};
    for _ in 0..TIME_BORROW_SPIN {
        if let Ok(guard) = thr.time.try_borrow() {
            return Ok(guard);
        }
        axtask::yield_now();
    }
    thr.time
        .try_borrow()
        .map_err(|_| AxError::from(LinuxError::EAGAIN))
}

/// Poll the timer
pub fn poll_timer(task: &TaskInner) {
    let Some(thr) = task.try_as_thread() else {
        return;
    };
    let Ok(mut time) = thr.time.try_borrow_mut() else {
        // reentrant borrow, likely IRQ
        return;
    };
    time.poll(|signo| {
        send_signal_thread_inner(task, thr, SignalInfo::new_kernel(signo));
    });

    // Also check POSIX timers
    crate::task::posix_timer::poll_posix_timers();
}

/// Sets the timer state.
pub fn set_timer_state(task: &TaskInner, state: TimerState) {
    let Some(thr) = task.try_as_thread() else {
        return;
    };
    let Ok(mut time) = thr.time.try_borrow_mut() else {
        // reentrant borrow, likely IRQ
        return;
    };
    time.poll(|signo| {
        send_signal_thread_inner(task, thr, SignalInfo::new_kernel(signo));
    });
    time.set_state(state);
}

