        // no_std lacks display()/to_str()/to_string_lossy().
        let mut parts = alloc::vec::Vec::new();
        let mut cur = loc.clone();
        loop {
            parts.push(alloc::string::String::from(cur.name()));
            match cur.parent() {
                Some(p) => cur = p,
                None => break,
            }
