const DIR_PERMISSION: NodePermission = NodePermission::from_bits_truncate(0o755);

fn ensure_dir(fs: &FsContext, path: &str) -> LinuxResult<()> {
    if fs.resolve(path).is_err() {
        fs.create_dir(path, DIR_PERMISSION)?;
    }
    Ok(())
}

fn write_sysfs_file(fs: &FsContext, path: &str, body: &str) {
    use axfs::OpenResult;

    let Ok(open) = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(fs, path)
    else {
        return;
    };
    if let OpenResult::File(file) = open {
        let _ = file.write(body.as_bytes());
    }
}

/// LTP `tst_get_hwaddrs` reads `/sys/class/net/<iface>/address` and `mtu`.
fn sync_iface_sysfs_at(fs: &FsContext, iface: &Interface) {
    let dir = alloc::format!("/sys/class/net/{}", iface.name);
    if ensure_dir(fs, &dir).is_err() {
        return;
    }
    write_sysfs_file(
        fs,
        &alloc::format!("{dir}/address"),
        &alloc::format!("{}\n", iface.hw_addr_string()),
    );
    write_sysfs_file(
        fs,
        &alloc::format!("{dir}/mtu"),
        &alloc::format!("{}\n", iface.mtu),
    );
}

/// Sync one interface; acquires the global FS lock (safe only outside `mount_all`).
pub fn sync_iface_sysfs(name: &str, hwaddr: &str, mtu: u32) {
    let fs = FS_CONTEXT.lock();
    let dir = alloc::format!("/sys/class/net/{name}");
    if ensure_dir(&fs, &dir).is_err() {
        return;
    }
    write_sysfs_file(&fs, &alloc::format!("{dir}/address"), &alloc::format!("{hwaddr}\n"));
    write_sysfs_file(&fs, &alloc::format!("{dir}/mtu"), &alloc::format!("{mtu}\n"));
}

/// Refresh `/sys/class/net/*` for the current network namespace only.
pub fn sync_current_netns_ifaces_sysfs_at(fs: &FsContext) {
    namespace::with_net_ns(|ns| {
        for iface in ns.interfaces() {
            sync_iface_sysfs_at(fs, iface);
        }
    });
}

/// Refresh `/sys/class/net/*` for the current network namespace.
pub fn sync_current_netns_ifaces_sysfs() {
    let fs = FS_CONTEXT.lock();
    sync_current_netns_ifaces_sysfs_at(&fs);
}

/// Refresh `/sys/class/net/*/address` using an already-held `FsContext`.
pub fn sync_all_ifaces_sysfs_at(fs: &FsContext) {
    sync_current_netns_ifaces_sysfs_at(fs);
    for ns in namespace::all_registered_netns() {
        for iface in ns.read().interfaces() {
            sync_iface_sysfs_at(fs, iface);
        }
    }
}

/// Refresh `/sys/class/net/*/address` after `mount -t sysfs` (LTP netns setup).
pub fn sync_all_ifaces_sysfs() {
    let fs = FS_CONTEXT.lock();
    sync_all_ifaces_sysfs_at(&fs);
}

/// Whether `addr` is configured on any known network namespace (for ICMP replies).
pub fn ipv4_reachable(addr: core::net::Ipv4Addr) -> bool {
    if namespace::with_net_ns(|ns| ns.has_ipv4_addr(addr)) {
        return true;
    }
    namespace::all_registered_netns()
        .iter()
        .any(|ns| ns.read().has_ipv4_addr(addr))
}

/// Whether `addr` is configured on any known network namespace (for ICMPv6 replies).
pub fn ipv6_reachable(addr: core::net::Ipv6Addr) -> bool {
    if namespace::with_net_ns(|ns| ns.has_ipv6_addr(addr)) {
        return true;
    }
    namespace::all_registered_netns()
        .iter()
        .any(|ns| ns.read().has_ipv6_addr(addr))
}

