/// Mount all filesystems
pub fn mount_all() -> LinuxResult<()> {
    info!("Initialize pseudofs...");

    let fs = FS_CONTEXT.lock();
    mount_at(&fs, "/dev", dev::new_devfs())?;
    mount_at(&fs, "/dev/shm", {
        let (fs, inst) = tmp::MemoryFs::new_with_mount_flags(0);
        inst.set_max_size(64 * 1024 * 1024); // 64 MiB
        fs
    })?;
    mount_at(&fs, "/tmp", {
        let (fs, inst) = tmp::MemoryFs::new_with_mount_flags(0);
        inst.set_max_size(256 * 1024 * 1024); // 256 MiB
        fs
    })?;
    mount_at(&fs, "/proc", proc::new_procfs())?;

    mount_at(&fs, "/sys", {
        let (fs, inst) = tmp::MemoryFs::new_with_mount_flags(0);
        inst.set_max_size(64 * 1024 * 1024); // 64 MiB
        fs
    })?;
    // Create /sys/class so we can mount net underneath it.
    if fs.resolve("/sys/class").is_err() {
        fs.create_dir("/sys/class", DIR_PERMISSION)?;
    }
    mount_at(&fs, "/sys/class/net", sys::new_sys_class_net_fs())?;
    // /sys/module/vcan — LTP CAN tests probe this to decide whether the vcan
    // driver is available.  Create as plain directories on the MemoryFs.
    for dir in &["/sys/module", "/sys/module/vcan", "/sys/module/veth", "/sys/module/ip_vti"] {
        if fs.resolve(dir).is_err() {
            fs.create_dir(dir, DIR_PERMISSION)?;
        }
    }
    // /sys/kernel/mm/hugepages/ — LTP futex_wake04 checks if this directory
    // exists to determine whether hugetlbfs is supported.
    for dir in &["/sys/kernel", "/sys/kernel/mm", "/sys/kernel/mm/hugepages"] {
        if fs.resolve(dir).is_err() {
            fs.create_dir(dir, DIR_PERMISSION)?;
        }
    }
    // /sys/kernel/debug/ — LTP ftrace tests look for debugfs tracing here.
    for dir in &["/sys/kernel/debug"] {
        if fs.resolve(dir).is_err() {
            fs.create_dir(dir, DIR_PERMISSION)?;
        }
    }
    mount_at(
        &fs,
        "/sys/kernel/debug/tracing",
        tracing::new_tracing_fs(),
    )?;
    let mut path = PathBuf::new();
    for comp in Path::new("/sys/class/graphics/fb0/device").components() {
        path.push(comp.as_str());
        if fs.resolve(&path).is_err() {
            fs.create_dir(&path, DIR_PERMISSION)?;
        }
    }
    path.push("subsystem");
    fs.symlink("whatever", &path)?;
    crate::net::init(&fs);
    drop(fs);

    #[cfg(feature = "dev-log")]
    dev::bind_dev_log().expect("Failed to bind /dev/log");

    Ok(())
}

