impl ExeFileNode {
    fn with_cache<R>(&self, f: impl FnOnce(&CachedFile) -> VfsResult<R>) -> VfsResult<R> {
        let task = self.task.upgrade().ok_or(VfsError::NotFound)?;
        let guard = task.as_thread().proc_data.exe_cache.read();
        let cache = guard.as_ref().ok_or(VfsError::NotFound)?;
        f(cache)
    }
}

