fn proc_data_for_procfs_pid_token(pid_token: &str) -> Option<Arc<ProcessData>> {
    if pid_token == "self" {
        return Some(current().as_thread().proc_data.clone());
    }
    if pid_token.is_empty() || !pid_token.chars().all(|c| c.is_ascii_digit()) {
        return None;
    }
    let id: u32 = pid_token.parse().ok()?;
    let pid = id as Pid;
    get_process_data(pid)
        .ok()
        .or_else(|| get_task(pid).ok().map(|t| t.as_thread().proc_data.clone()))
}

/// Linux `/proc/[pid]/exe`: `readlink` shows the path, but `open` / `execve` must use the real ELF.
/// Used by syscall layer so loaders (e.g. musl `ldd`) and `execve("/proc/self/exe")` behave like Linux.
pub(crate) fn rewrite_proc_exe_path_for_open(path: &str) -> Option<String> {
    const PREFIX: &str = "/proc/";
    if !path.starts_with(PREFIX) {
        return None;
    }
    let rest = path.strip_prefix(PREFIX)?;
    let pid_part = rest.strip_suffix("/exe")?;
    let proc_data = proc_data_for_procfs_pid_token(pid_part)?;
    let exe = proc_data.exe_path.read();
    let s = exe.as_str();
    if s.is_empty() {
        None
    } else {
        Some(String::from(s))
    }
}

