use alloc::{string::ToString, sync::Arc, vec::Vec};
use core::ffi::c_char;

use axerrno::{AxError, AxResult};
use axfs::FS_CONTEXT;
use axhal::uspace::UserContext;
use axtask::current;
use starry_vm::vm_load_until_nul;

use crate::{
    config::USER_HEAP_BASE,
    file::FD_TABLE,
    mm::{linux_exec_vecs, load_user_app, vm_load_string},
    pseudofs::rewrite_proc_exe_path_for_open,
    task::AsThread,
};

pub fn sys_execve(
    uctx: &mut UserContext,
    path: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
) -> AxResult<isize> {
    let mut path = vm_load_string(path)?;
    if let Some(real) = rewrite_proc_exe_path_for_open(&path) {
        path = real;
    }

    let mut args = if argv.is_null() {
        // Handle NULL argv: Linux uses the path as argv[0] in this case.
        Vec::new()
    } else {
        vm_load_until_nul(argv)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };
    // If args is empty (NULL argv or empty array), use path as argv[0].
    // app_stack_region panics on empty args; Linux always has at least argv[0].
    if args.is_empty() {
        args.push(path.clone());
    }

    let mut envs = if envp.is_null() {
        Vec::new()
    } else {
        vm_load_until_nul(envp)?
            .into_iter()
            .map(vm_load_string)
            .collect::<Result<Vec<_>, _>>()?
    };
    // Ensure TST_TIMEOUT has a sane default for every spawned process.
    if !envs.iter().any(|e| e.starts_with("TST_TIMEOUT=")) {
        // TST_TIMEOUT=-1 disables the LTP internal timeout timer.
        // This is a workaround for busybox ash on loongarch64 where
        // _tst_multiply_timeout() produces "sh: out of range" due to
        // cross-scope `local` variable resolution bugs when TST_TIMEOUT
        // is not pre-set as an environment variable.
        envs.push("TST_TIMEOUT=-1".into());
    }

    // Handle .sh redirect BEFORE load_user_app so that `path` is the actual
    // interpreter (/bin/sh), not the script file.  Otherwise exe_path would
    // incorrectly point to the .sh script while exe_cache belongs to /bin/sh's
    // ELF, causing every later open of that .sh file to return cached ELF bytes
    // (→ "syntax error: bad function name").
    if path.ends_with(".sh") {
        let mut new_args = alloc::vec!["/bin/sh".to_string()];
        new_args.extend(args.iter().cloned());
        args = new_args;
        path = "/bin/sh".to_string();
    }

    debug!("sys_execve <= path: {path:?}, args: {args:?}, envs: {envs:?}");

    let curr = current();
    let proc_data = &curr.as_thread().proc_data;

    if proc_data.proc.threads().len() > 1 {
        // TODO: handle multi-thread case
        error!("sys_execve: multi-thread not supported");
        return Err(AxError::WouldBlock);
    }

    // Check execute permission (DAC) before loading ELF (LTP execve03).
    {
        let loc = FS_CONTEXT.lock().resolve(&path)?;
        let meta = loc.metadata()?;
        let perm = meta.mode.bits();
        let uid = proc_data.cred_euid.load(core::sync::atomic::Ordering::Relaxed);
        let gid = proc_data.cred_egid.load(core::sync::atomic::Ordering::Relaxed);
        crate::syscall::fs::dac_access(
            perm, meta.uid, meta.gid, uid, gid,
            false, false, true,
        )?;
    }

    let mut aspace = proc_data.aspace.lock();
    let (entry_point, user_stack_base, exe_cache) = match load_user_app(
        &mut aspace,
        Some(path.as_str()),
        &args,
        &envs,
    ) {
        Ok(result) => result,
        Err(e) => {
            error!(
                "sys_execve: load_user_app failed for '{path}': {e:?}; \
                 args={args:?}, envs={envs:?}"
            );
            return Err(e);
        }
    };
    drop(aspace);

    let loc = FS_CONTEXT.lock().resolve(&path)?;
    curr.set_name(loc.name());

    let exe_path_str = loc.absolute_path()?.to_string();
    *proc_data.exe_path.write() = exe_path_str;
    *proc_data.exe_cache.write() = Some(exe_cache);
    let argc = args.len();
    *proc_data.cmdline.write() = Arc::new(args);

    proc_data.set_heap_top(USER_HEAP_BASE);

    *proc_data.signal.actions.lock() = Default::default();

    // Clear set_child_tid after exec since the original address is no longer valid
    curr.as_thread().set_clear_child_tid(0);

    // Close CLOEXEC file descriptors
    let mut fd_table = FD_TABLE.write();
    let cloexec_fds = fd_table
        .ids()
        .filter(|it| fd_table.get(*it).unwrap().cloexec)
        .collect::<Vec<_>>();
    for fd in cloexec_fds {
        fd_table.remove(fd);
    }
    drop(fd_table);

    let (_, argv_ptr, envp_ptr) = linux_exec_vecs(user_stack_base.as_usize(), argc);

    // Reset the entire user context so that stale register values from the
    // previous process (e.g. the `tp` thread pointer that was pointing to the
    // old TLS block, now unmapped) do not survive across execve.  Linux clears
    // all GP registers on exec; failing to do so can cause the new program's
    // dynamic linker to segfault when it reads `tp` before initialising TLS.
    *uctx = UserContext::new(entry_point.as_usize(), user_stack_base, argc);
    uctx.set_arg1(argv_ptr);
    uctx.set_arg2(envp_ptr);
    Ok(0)
}

/// execveat(dirfd, pathname, argv, envp, flags) — execute program relative to dirfd.
pub fn sys_execveat(
    uctx: &mut UserContext,
    dirfd: i32,
    pathname: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
    flags: i32,
) -> AxResult<isize> {
    use linux_raw_sys::general::AT_EMPTY_PATH;

    let mut path = vm_load_string(pathname)?;
    // If pathname is empty and AT_EMPTY_PATH is set, use dirfd as the executable fd.
    if path.is_empty() && (flags & AT_EMPTY_PATH as i32) != 0 {
        // Resolve the fd to a path — fallback: use the path from the fd.
        if let Ok(f) = crate::file::get_file_like(dirfd) {
            path = f.path().to_string();
        } else {
            return Err(AxError::InvalidInput);
        }
    }
    // For simplicity, we ignore dirfd and resolve path globally (same as execve).
    // A full implementation would resolve path relative to dirfd.
    sys_execve(uctx, path.as_ptr() as *const c_char, argv, envp)
}

