        Self::default()
    }

    /// Waits if the given condition is met.
    ///
    /// Returns `false` if the condition is not met and no actual waiting
    /// occurs.  Returns `true` when explicitly woken via [`wake`](Self::wake).
    ///
    /// Uses `FnMut` so the condition can be re-evaluated on spurious polls
    /// without prematurely returning `true`.  Internally tracks whether the
    /// waker has been removed from the queue (genuine wake) or is still
    /// present (timer tick / spurious poll).
    pub fn wait_if(
        &self,
        bitset: u32,
        timeout: Option<Duration>,
        mut condition: impl FnMut() -> bool,
    ) -> AxResult<bool> {
        let enqueued = core::cell::Cell::new(false);
        block_on(interruptible(future::timeout(
            timeout,
            poll_fn(|cx| {
                let mut queue = self.queue.lock();
                if enqueued.get() {
                    // Already enqueued — we were polled again.  Check whether
                    // our waker is still in the queue:
                    // - still there → spurious poll (e.g. timer tick) → stay Pending
                    // - removed     → explicit wake via wake()       → Ready(true)
                    let waker = cx.waker();
                    if queue.iter().any(|(w, _)| w.will_wake(waker)) {
                        Poll::Pending
                    } else {
                        Poll::Ready(Ok(true))
                    }
                } else if !condition() {
                    Poll::Ready(Ok(false))
                } else {
                    queue.push_back((cx.waker().clone(), bitset));
                    enqueued.set(true);
                    Poll::Pending
                }
            }),
        )))??
    }

    /// Wakes up at most `count` tasks whose bitset intersects with the given
    /// bitmask.
    pub fn wake(&self, count: usize, mask: u32) -> usize {
        let mut woke = 0;
        self.queue.lock().retain(|(waker, bitset)| {
            if woke >= count || (bitset & mask) == 0 {
                true
            } else {
                waker.wake_by_ref();
                woke += 1;
                false
            }
        });
        woke
    }

    /// Checks if the wait queue is empty.
    pub fn is_empty(&self) -> bool {
        self.queue.lock().is_empty()
    }

    /// Requeue at most `count` tasks to the target wait queue.
    pub fn requeue(&self, mut count: usize, target: &WaitQueue) -> usize {
        let tasks: Vec<_> = {
            let mut wq = self.queue.lock();
            count = count.min(wq.len());
            wq.drain(..count).collect()
        };
        if !tasks.is_empty() {
            let mut wq = target.queue.lock();
            wq.extend(tasks);
        }
        count
    }
}

/// A key that uniquely identifies a futex in the system.
pub enum FutexKey {
    /// A futex that is private to the current process.
    Private {
        /// The memory address of the futex.
        address: usize,
    },

    /// A futex in a shared memory region.
    Shared {
        /// The offset of the futex within the shared memory region.
        offset: usize,
        /// Anonymous shared pages, or a stable **file** identity `(device, inode)` mix for
        /// file-backed `MAP_SHARED` futexes so separate processes mapping the same inode share
        /// one wait-queue table (LTP `tst_checkpoint`, `autogroup01`, …).
        region: Result<Weak<SharedPages>, usize>,
    },
}

impl FutexKey {
    /// Creates a new `FutexKey`.
    pub fn new(aspace: &AddrSpace, address: usize) -> Self {
        if let Some(area) = aspace.find_area(VirtAddr::from_usize(address)) {
            match area.backend() {
                Backend::Shared(backend) => {
                    return Self::Shared {
                        offset: address - area.start().as_usize(),
                        region: Ok(Arc::downgrade(backend.pages())),
                    };
                }
                Backend::File(file) => {
                    return Self::Shared {
                        offset: address - area.start().as_usize(),
                        region: Err(file.futex_table_identity()),
                    };
                }
                _ => {}
            }
        }
        Self::Private { address }
    }

    /// Shortcut to create a `FutexKey` for the current task's address space.
    pub fn new_current(address: usize) -> Self {
        Self::new(&current().as_thread().proc_data.aspace.lock(), address)
    }

    fn as_usize(&self) -> usize {
        match self {
            FutexKey::Private { address } => *address,
            FutexKey::Shared { offset, .. } => *offset,
        }
    }
}

