/// Per-waiter descriptor for `futex_waitv(2)`.
/// Matches the Linux `struct futex_waitv` layout.
#[repr(C)]
#[derive(Debug, Clone, Copy)]
pub(crate) struct futex_waitv {
    val: u64,
    uaddr: u64,
    flags: u32,
    __reserved: u32,
}

/// Read a `futex_waitv` from user-space by reading each field separately.
/// This avoids needing `AnyBitPattern` derives which may not compile in all
/// Docker environments.
fn read_futex_waitv(ptr: *const futex_waitv) -> AxResult<futex_waitv> {
    // The struct layout is: val(u64) at +0, uaddr(u64) at +8,
    // flags(u32) at +16, __reserved(u32) at +20. Total 24 bytes.
    let base = ptr as *const u8;
    let val = unsafe { (base as *const u64).vm_read() }?;
    let uaddr = unsafe { base.add(8) as *const u64 }.vm_read()?;
    let flags = unsafe { base.add(16) as *const u32 }.vm_read()?;
    Ok(futex_waitv {
        val,
        uaddr,
        flags,
        __reserved: 0,
    })
}

/// Valid per-waiter flags for futex_waitv.
const FUTEX_WAITV_WAITER_FLAGS: u32 = linux_raw_sys::general::FUTEX_32 | FUTEX_PRIVATE_FLAG;
/// Maximum number of futexes in one futex_waitv call.
const FUTEX_WAITV_MAX: u32 = 128;

fn assert_unsigned(value: u32) -> AxResult<u32> {
    if (value as i32) < 0 {
        Err(AxError::InvalidInput)
    } else {
        Ok(value)
    }
}

fn duration_until_deadline(tv_sec: u64, tv_nsec: u32, now_sec: u64, now_nsec: u32) -> Duration {
    if (tv_sec, tv_nsec) <= (now_sec, now_nsec) {
        return Duration::ZERO;
    }
    let mut sec = tv_sec - now_sec;
    let nsec = if tv_nsec >= now_nsec {
        tv_nsec - now_nsec
    } else {
        sec -= 1;
        tv_nsec + 1_000_000_000 - now_nsec
    };
    Duration::new(sec, nsec)
}

pub fn sys_futex(
    uaddr: *const u32,
    futex_op: u32,
    value: u32,
    timeout: *const timespec,
    uaddr2: *mut u32,
    value3: u32,
) -> AxResult<isize> {
    debug!(
        "sys_futex <= uaddr: {uaddr:?}, futex_op: {futex_op}, value: {value}, uaddr2: {uaddr2:?}, \
         value3: {value3}",
    );

    let key = FutexKey::new_current(uaddr.addr());

    let futex_table = futex_table_for(&key);

    let command = futex_op & (FUTEX_CMD_MASK as u32);
    match command {
        FUTEX_WAIT | FUTEX_WAIT_BITSET => {
            // Fast path
            if uaddr.vm_read()? != value {
                return Err(AxError::WouldBlock);
            }

            let timeout = if let Some(ts) = timeout.nullable() {
                // FIXME: AnyBitPattern
                let ts = unsafe { ts.vm_read_uninit()?.assume_init() }.try_into_time_value()?;
                if command == FUTEX_WAIT_BITSET {
                    // FUTEX_WAIT_BITSET passes an absolute deadline; convert to a
                    // relative duration for the in-kernel wait helper.
                    let now = if (futex_op & (FUTEX_CLOCK_REALTIME as u32)) != 0 {
                        wall_time()
                    } else {
                        monotonic_time()
                    };
                    let rel = duration_until_deadline(
                        ts.as_secs(),
                        ts.subsec_nanos(),
                        now.as_secs(),
                        now.subsec_nanos(),
                    );
                    // Deadline already expired: return ETIMEDOUT immediately instead
                    // of passing Duration::ZERO to future::timeout, which may be
                    // interpreted as "no timeout" and block forever.
                    if rel.is_zero() {
                        return Err(AxError::from(LinuxError::ETIMEDOUT));
                    }
                    Some(rel)
                } else {
                    Some(ts)
                }
            } else {
                None
            };

            let futex = futex_table.get_or_insert(&key);

            let bitset = if command == FUTEX_WAIT_BITSET {
                value3
            } else {
                u32::MAX
            };

            // The fast-path check above already verified *uaddr == value.
            if !futex
                .wq
                .wait_if(bitset, timeout, || uaddr.vm_read() == Ok(value))?
            {
                // Timeout: Linux returns ETIMEDOUT (errno 110), not EWOULDBLOCK.
                return Err(AxError::from(LinuxError::ETIMEDOUT));
            }

            // FUTEX_WAIT should not return EOWNERDEAD directly.
            // Robust-mutex recovery is detected from the user futex word's
            // OWNER_DIED bit in userspace lock slow path.
            Ok(0)
        }
        FUTEX_WAKE | FUTEX_WAKE_BITSET => {
            let futex = futex_table.get(&key);
            let mut count = 0;
            if let Some(futex) = futex {
                let bitset = if command == FUTEX_WAKE_BITSET {
                    value3
                } else {
                    u32::MAX
                };
                count = futex.wq.wake(value as _, bitset);
