    tid: u32,
    head: *mut *const robust_list_head,
    size: *mut usize,
) -> AxResult<isize> {
    // Permission check: non-root users cannot access other processes' robust lists.
    // This must happen before the task lookup to match Linux error code ordering (EPERM before ESRCH).
    if tid != 0 {
        let curr = current();
        let pd = &curr.as_thread().proc_data;
        let euid = pd.cred_euid.load(core::sync::atomic::Ordering::Relaxed);
        if euid != 0 {
            // Non-root: can only access own robust list (tid == 0, handled above)
            return Err(LinuxError::EPERM.into());
        }
    }
    let task = get_task(tid)?;
    head.vm_write(task.as_thread().robust_list_head() as _)?;
    size.vm_write(size_of::<robust_list_head>())?;

    Ok(0)
}

