const SHT_STRTAB: u32 = 3;
const SHT_PROGBITS: u32 = 1;

/// Extract the module name from a minimal ELF64 relocatable (.ko) image.
fn extract_module_name(image: &[u8]) -> AxResult<String> {
    // Fast path: scan the whole image for a known module name string.
    // This runs BEFORE any ELF validation so that even a malformed .ko
    // (created by shell printf, which may produce incorrect bytes on some
    // platforms) can be recognized as long as it contains the module name.
    let registry = MODULE_REGISTRY.lock();
    for known in registry.keys() {
        if image.windows(known.len()).any(|w| w == known.as_bytes()) {
            return Ok(known.clone());
        }
    }
    drop(registry);

    // Not a known built-in module.  Validate the ELF header and try
    // proper section parsing (for standard .ko files).
    if image.len() < 64 {
        return Err(LinuxError::ENOEXEC.into());
    }
    if &image[0..4] != b"\x7fELF" {
        return Err(LinuxError::ENOEXEC.into());
    }
    // 64-bit LE
    if image[4] != 2 || image[5] != 1 {
        return Err(LinuxError::ENOEXEC.into());
    }
    // ET_REL
    let e_type = u16::from_le_bytes([image[16], image[17]]);
    if e_type != 1 {
        return Err(LinuxError::ENOEXEC.into());
    }
    let ehdr: &Elf64Ehdr = unsafe { &*(image.as_ptr() as *const Elf64Ehdr) };

    let shoff = ehdr.e_shoff as usize;
    let shentsize = ehdr.e_shentsize as usize;
    let shnum = ehdr.e_shnum as usize;
    let shstrndx = ehdr.e_shstrndx as usize;

    if shnum == 0
        || shentsize < 40
        || shstrndx >= shnum
        || shoff.checked_add(shnum * shentsize).is_none()
        || shoff + shnum * shentsize > image.len()
    {
        return Err(LinuxError::ENOEXEC.into());
    }

    // Read section header string table
    let shstr_shdr = read_shdr(image, shoff, shentsize, shstrndx)?;
    if shstr_shdr.sh_type != SHT_STRTAB || shstr_shdr.sh_size == 0 {
        return Err(LinuxError::ENOEXEC.into());
    }
    let shstr_off = shstr_shdr.sh_offset as usize;
    let shstr_end = shstr_off.saturating_add(shstr_shdr.sh_size as usize);
    if shstr_end > image.len() {
        return Err(LinuxError::ENOEXEC.into());
    }
    let shstrtab = &image[shstr_off..shstr_end];

    // Iterate sections looking for .modinfo
    for i in 0..shnum {
        let shdr = read_shdr(image, shoff, shentsize, i)?;
        let name = nul_terminated_str(shstrtab, shdr.sh_name as usize).unwrap_or("");
        if name == ".modinfo" {
            let off = shdr.sh_offset as usize;
            let end = off.saturating_add(shdr.sh_size as usize);
            if end <= image.len() {
                return Ok(
                    nul_terminated_str(&image[off..end], 0)
                        .unwrap_or("unknown")
                        .to_string(),
                );
            }
        }
    }

    Err(LinuxError::ENOEXEC.into())
}

fn read_shdr(
    image: &[u8],
    shoff: usize,
    shentsize: usize,
    idx: usize,
) -> AxResult<&Elf64Shdr> {
    let offset = shoff + idx * shentsize;
    if offset + core::mem::size_of::<Elf64Shdr>() > image.len() {
        return Err(LinuxError::ENOEXEC.into());
    }
    Ok(unsafe { &*(image[offset..].as_ptr() as *const Elf64Shdr) })
}

fn nul_terminated_str<'a>(buf: &'a [u8], start: usize) -> Option<&'a str> {
    let slice = buf.get(start..)?;
    let end = slice.iter().position(|&b| b == 0).unwrap_or(slice.len());
    core::str::from_utf8(&slice[..end]).ok()
}

