    if tid == 0 {
        return Ok(current().clone());
    }
    if let Some(task) = TASK_TABLE.read().get(&tid) {
        return Ok(task);
    }
    for task in tasks() {
        if task.as_thread().proc_data.proc.pid() == tid {
            return Ok(task);
        }
    }
    Err(AxError::NoSuchProcess)
}

