/// Proxy ops for an immediate child entry of a bind-mount proxy root.
///
/// Its `reference` has `parent = Some(proxy_root)` so that `collect_absolute_path`
/// stops at the proxy root (which has `reference.parent = None`) and does NOT
/// continue into the source filesystem's parent chain.  This ensures
/// `Location::absolute_path()` returns the correct path inside the bind mount.
///
/// The proxy child has its **own** `DirNode` (and thus its own `mountpoint` Mutex),
/// which means VFS `mount()` / `unmount()` on this entry work independently from
/// the source entry.  Operations are delegated to the source child for content.
struct BindProxyChildOps {
    source: DirEntry,
}

impl NodeOps for BindProxyChildOps {
    fn inode(&self) -> u64 {
        self.source.inode()
    }
    fn metadata(&self) -> VfsResult<Metadata> {
        self.source.metadata()
    }
    fn update_metadata(&self, update: MetadataUpdate) -> VfsResult<()> {
        self.source.update_metadata(update)
    }
    fn filesystem(&self) -> &dyn FilesystemOps {
        self.source.filesystem()
    }
    fn sync(&self, data_only: bool) -> VfsResult<()> {
        self.source.sync(data_only)
    }
    fn flags(&self) -> NodeFlags {
        self.source.flags()
    }
    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync> {
        self
    }
}

impl DirNodeOps for BindProxyChildOps {
    fn read_dir(&self, offset: u64, sink: &mut dyn DirEntrySink) -> VfsResult<usize> {
        self.source.as_dir()?.read_dir(offset, sink)
    }
    fn lookup(&self, name: &str) -> VfsResult<DirEntry> {
        self.source.as_dir()?.lookup(name)
    }
    fn create(&self, name: &str, node_type: NodeType, permission: NodePermission) -> VfsResult<DirEntry> {
        self.source.as_dir()?.create(name, node_type, permission)
    }
    fn link(&self, name: &str, node: &DirEntry) -> VfsResult<DirEntry> {
        self.source.as_dir()?.link(name, node)
    }
    fn unlink(&self, name: &str) -> VfsResult<()> {
        let dir = self.source.as_dir()?;
        let child = dir.lookup(name)?;
        dir.unlink(name, child.is_dir())
    }
    fn rename(&self, src_name: &str, dst_dir: &DirNode, dst_name: &str) -> VfsResult<()> {
        self.source.as_dir()?.rename(src_name, dst_dir, dst_name)
    }
}

