/// Create a new user task.
pub fn new_user_task(name: &str, mut uctx: UserContext, set_child_tid: usize) -> TaskInner {
    TaskInner::new(
        move || {
            let curr = axtask::current();

            if let Some(tid) = (set_child_tid as *mut Pid).nullable() {
                tid.vm_write(curr.id().as_u64() as Pid).ok();
            }

            info!("Enter user space: ip={:#x}, sp={:#x}", uctx.ip(), uctx.sp());

            let thr = curr.as_thread();
            while !thr.pending_exit() {
                let reason = uctx.run();

                set_timer_state(&curr, TimerState::Kernel);

                match reason {
                    ReturnReason::Syscall => {
                        // Save the signal mask at syscall entry.  glibc
                        // wrappers (e.g. pthread_join) block SIGCANCEL
                        // before the syscall; restoring this mask at exit
                        // allows the cancellation signal to be delivered
                        // before the wrapper processes the result.
                        let saved_sigmask = thr.signal.blocked();

                        handle_syscall(&mut uctx);

                        // Temporarily restore the pre-syscall mask so that
                        // signals blocked by the wrapper can be dequeued.
                        let post_syscall_mask = thr.signal.set_blocked(saved_sigmask);

                        // Detect whether a signal handler was installed
                        // (which ORs sa_mask into self.blocked).
                        let blocked_before = thr.signal.blocked();

                        if !unblock_next_signal() {
                            while check_signals(
                                thr,
                                &mut uctx,
                                Some(saved_sigmask),
                            ) {}
                        }

                        // Only restore the post-syscall mask if no handler
                        // was installed.  A handler's sa_mask changes must
                        // be preserved so the handler runs with the correct
                        // signal mask; rt_sigreturn will restore the
                        // pre-handler mask from the signal frame.
                        if signal_set_eq(thr.signal.blocked(), blocked_before) {
                            thr.signal.set_blocked(post_syscall_mask);
                        }
                    }
                    ReturnReason::PageFault(addr, flags) => {
                        if !thr.proc_data.aspace.lock().handle_page_fault(addr, flags) {
                            let pid = thr.proc_data.proc.pid();
                            let tid = curr.id().as_u64();
                            let pc = uctx.ip();
                            let sp = uctx.sp();
                            let raw_last_sysno = thr.last_syscall_no();
                            let last_syscall = raw_last_sysno.and_then(|n| Sysno::new(n as _));
                            warn!(
                                "user segv: pid={pid}, tid={tid}, fault_addr={:#x}, pc={:#x}, sp={:#x}, pf_flags={:?}, last_syscall={:?}, raw_sysno={:?}",
                                addr,
                                pc,
                                sp,
                                flags,
                                last_syscall,
                                raw_last_sysno
                            );

                            raise_signal_fatal(SignalInfo::new_kernel(Signo::SIGSEGV))
                                .expect("Failed to send SIGSEGV");
                        }
                    }
                    ReturnReason::Interrupt => {}
                    #[allow(unused_labels)]
                    ReturnReason::Exception(exc_info) => 'exc: {
                        // TODO: detailed handling
                        let signo = match exc_info.kind() {
                            ExceptionKind::Misaligned => {
                                #[cfg(target_arch = "loongarch64")]
                                if unsafe { uctx.emulate_unaligned() }.is_ok() {
                                    break 'exc;
                                }
                                Signo::SIGBUS
                            }
                            ExceptionKind::Breakpoint => Signo::SIGTRAP,
                            ExceptionKind::IllegalInstruction => Signo::SIGILL,
                            _ => Signo::SIGTRAP,
                        };
                        raise_signal_fatal(SignalInfo::new_kernel(signo))
                            .expect("Failed to send SIGTRAP");
                    }
                    r => {
                        warn!("Unexpected return reason: {r:?}");
                        raise_signal_fatal(SignalInfo::new_kernel(Signo::SIGSEGV))
                            .expect("Failed to send SIGSEGV");
                    }
                }

                if !unblock_next_signal() {
                    while check_signals(thr, &mut uctx, None) {}
                }

                set_timer_state(&curr, TimerState::User);
                curr.clear_interrupt();
            }
            // Propagate the real exit code instead of relying on task_entry's
            // hardcoded `crate::exit(0)` which would discard the process exit code
            // stored by do_exit (sys_exit / sys_exit_group).
            let exit_code = thr.proc_data.proc.exit_code();
            axtask::exit(exit_code);
        },
        name.into(),
        crate::config::KERNEL_STACK_SIZE,
    )
}

