/// Linux `inotify` event masks used by LTP.
pub const IN_ACCESS: u32 = 0x0000_0001;
pub const IN_MODIFY: u32 = 0x0000_0002;
pub const IN_ATTRIB: u32 = 0x0000_0004;
pub const IN_CLOSE_WRITE: u32 = 0x0000_0008;
pub const IN_CLOSE_NOWRITE: u32 = 0x0000_0010;
pub const IN_OPEN: u32 = 0x0000_0020;
pub const IN_DELETE: u32 = 0x0000_0200;
pub const IN_ISDIR: u32 = 0x4000_0000;

const INOTIFY_EVENT_SIZE: usize = 16;

struct WatchEntry {
    ino: Arc<InotifyFd>,
    mask: u32,
    path: String,
    is_dir: bool,
}

static NEXT_WD: AtomicI32 = AtomicI32::new(1);
static WATCHES: Mutex<BTreeMap<i32, WatchEntry>> = Mutex::new(BTreeMap::new());

struct InotifyFd {
    nonblocking: AtomicBool,
    events: Mutex<VecDeque<Vec<u8>>>,
}

impl InotifyFd {
    fn push_event(&self, wd: i32, mask: u32) {
        self.push_event_named(wd, mask, "");
    }

    fn push_event_named(&self, wd: i32, mask: u32, name: &str) {
        let name_bytes = name.as_bytes();
        let name_len = if name.is_empty() {
            0
        } else {
            name_bytes.len() + 1
        };
        let padded = (name_len + 3) & !3;
        let total = INOTIFY_EVENT_SIZE + padded;
        let mut ev = vec![0u8; total];
        ev[0..4].copy_from_slice(&wd.to_ne_bytes());
        ev[4..8].copy_from_slice(&mask.to_ne_bytes());
        ev[12..16].copy_from_slice(&(name_len as u32).to_ne_bytes());
        if name_len > 0 {
            ev[INOTIFY_EVENT_SIZE..INOTIFY_EVENT_SIZE + name_bytes.len()]
                .copy_from_slice(name_bytes);
        }
        self.events.lock().push_back(ev);
    }
}

fn resolve_watch_path(path: &str) -> AxResult<String> {
    with_fs(AT_FDCWD as _, |fs| {
        let loc = fs.resolve(path)?;
        Ok(loc
            .absolute_path()
            .map_err(|_| AxError::NotFound)?
            .to_string())
    })
}

fn watch_is_dir(path: &str) -> bool {
    with_fs(AT_FDCWD as _, |fs| {
        let loc = fs.resolve(path)?;
        Ok(loc.entry().metadata()?.node_type == NodeType::Directory)
    })
    .unwrap_or(false)
}

/// Emit inotify events for every watch on `path`.
pub fn inotify_emit_path(path: &str, mask: u32) {
    let watches = WATCHES.lock();
    for (wd, watch) in watches.iter() {
        if watch.path == path {
            if watch.mask & mask != 0 {
                watch.ino.push_event(*wd, mask);
            }
            continue;
        }
        if !watch.is_dir {
            continue;
        }
        let Some(rest) = path.strip_prefix(watch.path.as_str()) else {
            continue;
        };
        let rest = rest.strip_prefix('/').unwrap_or(rest);
        if rest.is_empty() || rest.contains('/') {
            continue;
        }
        if watch.mask & mask != 0 {
            watch.ino.push_event_named(*wd, mask | IN_ISDIR, rest);
        }
    }
}

pub fn inotify_emit_fd(fd: i32, mask: u32) {
    if let Ok(f) = get_file_like(fd) {
        if let Ok(file) = f.downcast_arc::<File>() {
            inotify_emit_path(&file.path(), mask);
        }
    }
}

fn fd_opened_for_write(fd: i32) -> bool {
    if let Ok(f) = get_file_like(fd) {
        if let Ok(file) = f.downcast_arc::<File>() {
            return file.inner().flags().contains(FileFlags::WRITE);
        }
    }
    false
}

pub fn inotify_emit_close(fd: i32, writable: bool) {
    let mask = if writable {
        IN_CLOSE_WRITE
    } else {
        IN_CLOSE_NOWRITE
    };
    inotify_emit_fd(fd, mask);
}

impl FileLike for InotifyFd {
    fn read(&self, dst: &mut crate::file::IoDst) -> AxResult<usize> {
        loop {
            if let Some(ev) = self.events.lock().pop_front() {
                return dst.write(&ev);
            }
            if self.nonblocking.load(Ordering::Relaxed) {
                return Err(AxError::WouldBlock);
            }
            axtask::yield_now();
        }
    }

    fn path(&self) -> Cow<'_, str> {
        "anon_inode:inotify".into()
    }

    fn nonblocking(&self) -> bool {
        self.nonblocking.load(Ordering::Relaxed)
    }

    fn set_nonblocking(&self, nonblocking: bool) -> AxResult {
        self.nonblocking.store(nonblocking, Ordering::Relaxed);
        Ok(())
    }
}

impl Pollable for InotifyFd {
    fn poll(&self) -> IoEvents {
        if !self.events.lock().is_empty() {
            IoEvents::IN
        } else {
            IoEvents::empty()
        }
    }

    fn register(&self, _context: &mut Context<'_>, _events: IoEvents) {}
}

pub fn sys_inotify_init1(flags: u32) -> AxResult<isize> {
    debug!("sys_inotify_init1 <= flags: {flags:#x}");
    let cloexec = flags & O_CLOEXEC != 0;
    let nonblock = flags & O_NONBLOCK != 0;
    InotifyFd {
        nonblocking: AtomicBool::new(nonblock),
        events: Mutex::new(VecDeque::new()),
    }
    .add_to_fd_table(cloexec)
    .map(|fd| fd as isize)
}

pub fn sys_inotify_add_watch(fd: i32, pathname: *const c_char, mask: u32) -> AxResult<isize> {
    debug!("sys_inotify_add_watch <= fd: {fd}, mask: {mask:#x}");
    let path = vm_load_string(pathname)?;
    let abs = resolve_watch_path(&path)?;
    let is_dir = watch_is_dir(&path);
    let f = get_file_like(fd)?;
    let ino = f
        .downcast_arc::<InotifyFd>()
        .map_err(|_| AxError::BadFileDescriptor)?;
    let wd = NEXT_WD.fetch_add(1, Ordering::Relaxed);
    WATCHES.lock().insert(
        wd,
        WatchEntry {
            ino,
            mask,
            path: abs,
            is_dir,
        },
    );
    Ok(wd as isize)
}

pub fn sys_inotify_rm_watch(fd: i32, wd: i32) -> AxResult<isize> {
    debug!("sys_inotify_rm_watch <= fd: {fd}, wd: {wd}");
    let _ = get_file_like(fd)?;
    WATCHES.lock().remove(&wd);
    Ok(0)
}

