/// Mutably borrow the current thread's [`TimeManager`], yielding on `RefCell` conflict.
pub(crate) fn borrow_thread_time_mut(
    thr: &Thread,
) -> Result<core::cell::RefMut<'_, TimeManager>, axerrno::AxError> {
    use axerrno::{AxError, LinuxError};
    for _ in 0..TIME_BORROW_SPIN {
        if let Ok(guard) = thr.time.try_borrow_mut() {
            return Ok(guard);
        }
        axtask::yield_now();
    }
    thr.time
        .try_borrow_mut()
        .map_err(|_| AxError::from(LinuxError::EAGAIN))
}

