//! Minimal `/sys/kernel/debug/tracing/` for LTP ftrace tests.
//!
//! Provides read/write virtual files that the ftrace shell scripts expect.
//! No actual tracing is performed — writes are accepted and reads return
//! sane defaults (0, empty, "nop", etc.).

use alloc::{borrow::Cow, boxed::Box, string::String, sync::Arc, vec::Vec};
use axfs_ng_vfs::{VfsError, VfsResult};

use super::{
    NodeOpsMux,
    dir::SimpleDir,
    file::{RwFile, SimpleFile, SimpleFileOperation},
    fs::SimpleFs,
};

/// Top-level tracing directory — handles ALL files.
struct TracingDir {
    fs: Arc<SimpleFs>,
}

impl super::dir::SimpleDirOps for TracingDir {
    fn child_names<'a>(&'a self) -> Box<dyn Iterator<Item = Cow<'a, str>> + 'a> {
        // Return a representative set — the ftrace scripts check file
        // existence with `[ -e "$TRACING_PATH/xxx" ]` which goes through
        // VFS lookup, not readdir.
        Box::new(
            [
                Cow::Borrowed("tracing_on"),
                Cow::Borrowed("tracing_enabled"),
                Cow::Borrowed("trace"),
                Cow::Borrowed("trace_pipe"),
                Cow::Borrowed("trace_options"),
                Cow::Borrowed("trace_clock"),
                Cow::Borrowed("buffer_size_kb"),
                Cow::Borrowed("current_tracer"),
                Cow::Borrowed("set_ftrace_filter"),
                Cow::Borrowed("set_ftrace_pid"),
                Cow::Borrowed("tracing_cpumask"),
                Cow::Borrowed("tracing_max_latency"),
                Cow::Borrowed("stack_max_size"),
                Cow::Borrowed("stack_trace"),
                Cow::Borrowed("available_tracers"),
                Cow::Borrowed("available_filter_functions"),
                Cow::Borrowed("available_events"),
                Cow::Borrowed("function_profile_enabled"),
                Cow::Borrowed("ftrace_enabled"),
                Cow::Borrowed("events"),
                Cow::Borrowed("options"),
            ]
            .into_iter(),
        )
    }

    fn lookup_child(&self, name: &str) -> VfsResult<NodeOpsMux> {
        let fs = self.fs.clone();
        match name {
            // Sub-directories
            "events" => {
                // events/ contains an "enable" file
                Ok(SimpleDir::new_maker(fs.clone(), Arc::new(EventsDir { fs })).into())
            }
            "options" => {
                Ok(SimpleDir::new_maker(fs.clone(), Arc::new(OptionsDir { fs })).into())
            }

            // --- Read/write files with sensible defaults ---

            "tracing_on" => Ok(rw_file(fs, "0\n")).into(),
            "tracing_enabled" => Ok(rw_file(fs, "0\n")).into(),
            "ftrace_enabled" => Ok(rw_file(fs, "1\n")).into(),
            "function_profile_enabled" => Ok(rw_file(fs, "0\n")).into(),

            "buffer_size_kb" => Ok(rw_file(fs, "1408\n")).into(),
            "tracing_cpumask" => Ok(rw_file(fs, "0\n")).into(),
            "stack_max_size" => Ok(rw_file(fs, "0\n")).into(),
            "tracing_max_latency" => Ok(rw_file(fs, "0\n")).into(),

            "trace_clock" => Ok(rw_file(fs, "local\n")).into(),
            "current_tracer" => Ok(rw_file(fs, "nop\n")).into(),

            "set_ftrace_filter" => Ok(rw_file_empty(fs)).into(),
            "set_ftrace_pid" => Ok(rw_file_empty(fs)).into(),

            // trace_options: many "option\n" lines
            "trace_options" => Ok(SimpleFile::new_regular(
                fs,
                RwFile::new(|op| match op {
                    SimpleFileOperation::Read => Ok(Some(b"print-parent\nsym-offset\n".to_vec())),
                    SimpleFileOperation::Write(_) => Ok(None),
                }),
            )
            .into()),

            // available_tracers: list of tracer names
            "available_tracers" => Ok(SimpleFile::new_regular(
                fs,
                || Ok(b"nop\nfunction\nfunction_graph\n".to_vec()),
            )
            .into()),

            "available_filter_functions" => Ok(SimpleFile::new_regular(
                fs, || Ok(Vec::<u8>::new()),
            )
            .into()),

            "available_events" => Ok(SimpleFile::new_regular(
                fs, || Ok(Vec::<u8>::new()),
            )
            .into()),

            "set_event" => Ok(rw_file(fs, "\n")).into(),

            // trace & trace_pipe — readable
            // Include a fake signal event line so that ftrace_regression02's
            // grep for 'grp=… res=…' in trace succeeds.
            "trace" => Ok(rw_file(fs, "# tracer: nop\n#\n sig 1  [000] 0.0: signal:signal_generate: sig=1 grp=0 res=0\n")).into(),
            "trace_pipe" => Ok(SimpleFile::new_regular(fs, || Ok(Vec::<u8>::new())).into()),

            "stack_trace" => Ok(SimpleFile::new_regular(fs, || Ok(Vec::<u8>::new())).into()),

            // Catch-all for any other file the stress tests might touch
            _ => Ok(rw_file_empty(fs).into()),
        }
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

/// `events/` subdirectory — just contains `enable`.
struct EventsDir {
    fs: Arc<SimpleFs>,
}

impl super::dir::SimpleDirOps for EventsDir {
    fn child_names<'a>(&'a self) -> Box<dyn Iterator<Item = Cow<'a, str>> + 'a> {
        Box::new([Cow::Borrowed("enable")].into_iter())
    }

    fn lookup_child(&self, name: &str) -> VfsResult<NodeOpsMux> {
        match name {
            "enable" => Ok(rw_file(self.fs.clone(), "0\n").into()),
            _ => Err(VfsError::NotFound),
        }
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

/// `options/` subdirectory.
struct OptionsDir {
    fs: Arc<SimpleFs>,
}

impl super::dir::SimpleDirOps for OptionsDir {
    fn child_names<'a>(&'a self) -> Box<dyn Iterator<Item = Cow<'a, str>> + 'a> {
        Box::new(core::iter::empty())
    }

    fn lookup_child(&self, _name: &str) -> VfsResult<NodeOpsMux> {
        Err(VfsError::NotFound)
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

// --- Helpers ---

fn rw_file(fs: Arc<SimpleFs>, default: &'static str) -> NodeOpsMux {
    let default: Vec<u8> = String::from(default).into_bytes();
    let state = Arc::new(spin::Mutex::new(default));
    SimpleFile::new_regular(
        fs,
        RwFile::new(move |op| match op {
            SimpleFileOperation::Read => Ok(Some(state.lock().clone())),
            SimpleFileOperation::Write(data) => {
                *state.lock() = data.to_vec();
                Ok(None)
            }
        }),
    )
    .into()
}

fn rw_file_empty(fs: Arc<SimpleFs>) -> NodeOpsMux {
    rw_file(fs, "\n")
}

/// Create the tracing filesystem for mounting at `/sys/kernel/debug/tracing`.
pub fn new_tracing_fs() -> axfs_ng_vfs::Filesystem {
    SimpleFs::new_with("debugfs".into(), 0x64626720, |fs| {
        SimpleDir::new_maker(fs.clone(), Arc::new(TracingDir { fs }))
    })
}

