/// /sys/class/net/ — lists all network devices dynamically.
struct SysClassNetRoot {
    fs: Arc<SimpleFs>,
}

impl SimpleDirOps for SysClassNetRoot {
    fn child_names<'a>(&'a self) -> Box<dyn Iterator<Item = Cow<'a, str>> + 'a> {
        let names: Vec<_> = axnet::get_service()
            .device_names()
            .into_iter()
            .map(Cow::Owned)
            .collect();
        Box::new(names.into_iter())
    }

    fn lookup_child(&self, name: &str) -> VfsResult<NodeOpsMux> {
        if axnet::get_service().device_index_by_name(name).is_some() {
            Ok(NodeOpsMux::Dir(SimpleDir::new_maker(
                self.fs.clone(),
                Arc::new(SysClassNetDeviceDir {
                    fs: self.fs.clone(),
                    ifname: String::from(name),
                }),
            )))
        } else {
            Err(VfsError::NotFound)
        }
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

/// /sys/class/net/<iface>/ — per-device attributes.
struct SysClassNetDeviceDir {
    fs: Arc<SimpleFs>,
    ifname: String,
}

impl SimpleDirOps for SysClassNetDeviceDir {
    fn child_names<'a>(&'a self) -> Box<dyn Iterator<Item = Cow<'a, str>> + 'a> {
        Box::new(
            [Cow::Borrowed("address"), Cow::Borrowed("flags"), Cow::Borrowed("mtu")].into_iter(),
        )
    }

    fn lookup_child(&self, name: &str) -> VfsResult<NodeOpsMux> {
        let fs = self.fs.clone();
        let ifname = self.ifname.clone();
        match name {
            "address" => {
                Ok(SimpleFile::new(fs, NodeType::RegularFile, move || {
                    let mac = axnet::get_service()
                        .device_mac(&ifname)
                        .unwrap_or([0x00, 0x00, 0x00, 0x00, 0x00, 0x00]);
                    Ok(format!(
                        "{:02x}:{:02x}:{:02x}:{:02x}:{:02x}:{:02x}\n",
                        mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]
                    ))
                })
                .into())
            }
            "flags" => Ok(SimpleFile::new(fs, NodeType::RegularFile, move || {
                // IFF_UP|IFF_BROADCAST|IFF_RUNNING|IFF_MULTICAST|IFF_ECHO
                // IFF_ECHO = 0x40000, suppresses LTP echo-detection TWARN.
                Ok(format!("0x41043\n"))
            })
            .into()),
            "mtu" => Ok(SimpleFile::new(fs, NodeType::RegularFile, move || {
                let mtu = axnet::get_service().device_mtu(&ifname).unwrap_or(1500);
                Ok(format!("{}\n", mtu))
            })
            .into()),
            _ => Err(VfsError::NotFound),
        }
    }

    fn is_cacheable(&self) -> bool {
        false
    }
}

/// Create a filesystem tree for /sys/class/net/.
pub fn new_sys_class_net_fs() -> axfs_ng_vfs::Filesystem {
    SimpleFs::new_with("sysfs".into(), 0x62656572, |fs| {
        SimpleDir::new_maker(fs.clone(), Arc::new(SysClassNetRoot { fs }))
    })
}

use alloc::{sync::Arc, vec, vec::Vec};

use axfs::{FS_CONTEXT, OpenOptions};
use axfs_ng_vfs::VfsResult;
use axsync::Mutex;

pub trait BlockDevice: Send + Sync {
    fn read_block(&self, block: u64) -> VfsResult<Vec<u8>>;
    fn write_block(&self, block: u64, data: &[u8]) -> VfsResult<()>;
    fn block_size(&self) -> usize;
    fn block_count(&self) -> u64;
    fn sync(&self) -> VfsResult<()>;
}

pub type DynBlockDevice = Arc<dyn BlockDevice>;

pub struct DiskImageBlockDevice {
    file: Mutex<axfs::File>,
    block_size: usize,
    block_count: u64,
}

impl DiskImageBlockDevice {
    pub fn open(path: &str, block_size: usize, block_count: u64) -> VfsResult<DynBlockDevice> {
        let file = {
            let fs = FS_CONTEXT.lock();
            OpenOptions::new()
                .read(true)
                .write(true)
                .direct(true)
                .create(true)
                .open(&fs, path)?
                .into_file()?
        };

        let expected_len = block_size as u64 * block_count;
        let curr_len = file.location().len()?;
        warn!(
            "journalfs blockdev open path={} curr_len={} expected_len={}",
            path, curr_len, expected_len
        );

        // Extend image size by zero-fill without touching existing data.
        if curr_len < expected_len {
            let padding = [0u8; 64 * 1024];
            let mut offset = curr_len;
            while offset < expected_len {
                let n = (expected_len - offset).min(padding.len() as u64) as usize;
                file.write_at(&padding[..n], offset)?;
                offset += n as u64;
            }
            file.sync(false)?;
        }

        Ok(Arc::new(Self {
            file: Mutex::new(file),
            block_size,
            block_count,
        }))
    }

    fn check_range(&self, block: u64) -> VfsResult<()> {
        if block >= self.block_count {
            return Err(axfs_ng_vfs::VfsError::InvalidInput);
        }
        Ok(())
    }
}

impl BlockDevice for DiskImageBlockDevice {
    fn read_block(&self, block: u64) -> VfsResult<Vec<u8>> {
        self.check_range(block)?;
        let mut buf = vec![0u8; self.block_size];
        let offset = block * self.block_size as u64;
        let file = self.file.lock();
        let mut done = 0;
        while done < self.block_size {
            let n = file.read_at(&mut buf[done..], offset + done as u64)?;
            if n == 0 {
                break;
            }
            done += n;
        }
        if done < self.block_size {
            warn!(
                "journalfs blockdev short read block={} offset={} read={}",
                block, offset, done
            );
        }
        Ok(buf)
    }

    fn write_block(&self, block: u64, data: &[u8]) -> VfsResult<()> {
        self.check_range(block)?;
        if data.len() > self.block_size {
            return Err(axfs_ng_vfs::VfsError::InvalidInput);
        }
        let mut buf = vec![0u8; self.block_size];
        buf[..data.len()].copy_from_slice(data);
        let offset = block * self.block_size as u64;
        let file = self.file.lock();

        let mut done = 0;
        while done < self.block_size {
            let n = file.write_at(&buf[done..], offset + done as u64)?;
            if n == 0 {
                return Err(axfs_ng_vfs::VfsError::Io);
            }
            done += n;
        }
        Ok(())
    }

    fn block_size(&self) -> usize {
        self.block_size
    }

    fn block_count(&self) -> u64 {
        self.block_count
    }

    fn sync(&self) -> VfsResult<()> {
        self.file.lock().sync(false)
    }
}

    if group_exit && !process.is_group_exited() {
        process.group_exit();
        let sig = SignalInfo::new_kernel(Signo::SIGKILL);
        for tid in process.threads() {
            let _ = send_signal_to_thread(None, tid, Some(sig.clone()));
        }
    }
